create table if not exists public.experiences_escapamex (
  id text not null,
  slug text not null,
  title text not null,
  category text not null,
  description text not null,
  short_description text not null,
  price numeric not null,
  price_max numeric null,
  currency text not null,
  image text not null,
  images jsonb not null,
  included jsonb not null,
  duration text not null,
  location text not null,
  rating numeric null default 0,
  reviews integer null default 0,
  featured boolean null default false,
  created_at timestamp without time zone null default now(),
  tafiras json null,
  constraint experiences_escapamex_pkey primary key (id),
  constraint experiences_escapamex_slug_key unique (slug)
);

INSERT INTO public.experiences_escapamex (id, slug, title, category, description, short_description, price, price_max, currency, image, images, included, duration, location, tafiras) VALUES ('6f79feb4-c3ee-511f-8653-32360799922d', 'experiencia-cena-show-ritmos-de-la-noche', 'Experiencia “Cena & Show Ritmos de la Noche”', 'Gastronomía', 'Disfruta de una velada mágica con cena gourmet y espectáculo en un entorno selvático.', 'Disfruta de una velada mágica con cena gourmet y espectáculo en un entorno selvático.', 3850.0, NULL, 'MXN', 'https://addyourexperience.com/wp-content/uploads/2026/04/20-300x300.jpg', '["https://addyourexperience.com/wp-content/uploads/2026/04/20-300x300.jpg", "https://addyourexperience.com/wp-content/uploads/2026/04/Cena-y-Show-Ritmos-de-la-Noche-1-300x300.jpg", "https://addyourexperience.com/wp-content/uploads/2026/04/Cena-y-Show-Ritmos-de-la-Noche-2-300x300.jpg"]', '["Transporte marítimo", "Cena", "Barra libre", "Show"]', '5.5 horas', 'México', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.experiences_escapamex (id, slug, title, category, description, short_description, price, price_max, currency, image, images, included, duration, location, tafiras) VALUES ('d973450f-6f63-546d-b01f-e0059b284276', 'experiencia-chichen-itza-historia-espectaculo-nocturno', 'Experiencia “Chichén Itzá: Historia & Espectáculo Nocturno”', 'Cultura', 'Vive una experiencia completa en una de las nuevas maravillas del mundo. Este recorrido combina la exploración guiada de Chichén Itzá durante el día con un impresionante espectáculo nocturno de luz y sonido que da vida a la historia de la civilización maya sobre la Pirámide de Kukulkán.', 'Vive una experiencia completa en una de las nuevas maravillas del mundo. Este recorrido combina la exploración guiada de Chichén Itzá durante el dí...', 2120.0, NULL, 'MXN', 'https://addyourexperience.com/wp-content/uploads/2026/04/9-300x300.jpg', '["https://addyourexperience.com/wp-content/uploads/2026/04/9-300x300.jpg", "https://addyourexperience.com/wp-content/uploads/2026/04/92-300x300.jpg", "https://addyourexperience.com/wp-content/uploads/2026/04/9-1-300x300.jpg"]', '["Transporte redondo desde Cancún", "Guía arqueológico certificado (español/inglés)", "Acceso a la zona arqueológica", "Almuerzo buffet", "Entrada al espectáculo nocturno", "Importante: El punto de encuentro será confirmado tras la reserva para una mejor organización del servicio."]', '10 a 12 horas', 'México', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO public.experiences_escapamex (id, slug, title, category, description, short_description, price, price_max, currency, image, images, included, duration, location, tafiras) VALUES ('94b3b33e-c534-5464-b7cd-74f88b234e49', 'experiencia-cozumel-reef-adventure', 'Experiencia “Cozumel Reef Adventure”', 'Aventura Acuática', 'Explora la espectacular isla de Cozumel, reconocida mundialmente por sus arrecifes. Esta experiencia te permitirá practicar snorkel en zonas privilegiadas, relajarte en playas de aguas cristalinas y disfrutar de un ambiente caribeño ideal para desconectar.', 'Explora la espectacular isla de Cozumel, reconocida mundialmente por sus arrecifes. Esta experiencia te permitirá practicar snorkel en zonas privil...', 5120.0, NULL, 'MXN', 'https://addyourexperience.com/wp-content/uploads/2026/04/10-300x300.jpg', '["https://addyourexperience.com/wp-content/uploads/2026/04/10-300x300.jpg", "https://addyourexperience.com/wp-content/uploads/2026/04/10-2-300x300.jpg", "https://addyourexperience.com/wp-content/uploads/2026/04/10-3-300x300.jpg"]', '["Transporte redondo desde Cancún", "Guía bilingüe", "Traslado marítimo a Cozumel", "Actividad de snorkel en arrecifes seleccionados", "Almuerzo tipo buffet o menú local", "Tiempo libre en playa", "Importante: El punto de encuentro será confirmado al realizar la reservación."]', '8 a 10 horas', 'Cozumel', NULL) ON CONFLICT (slug) DO NOTHING;
