INSERT INTO public.experiences_escapamex (id, slug, title, category, description, short_description, price, price_max, currency, image, images, included, duration, location, tafiras) VALUES ('855fb021-3700-5223-9e2e-a8ef52ec2411', 'experiencia-fiesta-flotante-xochimilco', 'Experiencia “Fiesta Flotante Xochimilco”', 'Aventura', 'Disfruta de una celebración única sobre los canales de Xochimilco con música, bebidas y ambiente festivo. Perfecto para grupos que buscan algo divertido y diferente. Cupo Máximo: 10 personas. Precios escalonados: 1-3 pers: $1,150 p/p, 4-6 pers: $1,050 p/p, 7+ pers: $950 p/p.', 'Disfruta de una celebración única sobre los canales de Xochimilco con música, bebidas y ambiente festivo. Perfecto para grupos que buscan algo dive...', 1150.0, NULL, 'MXN', 'https://addyourexperience.com/wp-content/uploads/2026/04/4-300x300.jpg', '["https://addyourexperience.com/wp-content/uploads/2026/04/4-300x300.jpg", "https://addyourexperience.com/wp-content/uploads/2026/04/4-2-300x300.jpg", "https://addyourexperience.com/wp-content/uploads/2026/04/4-3-300x300.jpg"]', '["Trajinera privada", "Barra de bebidas (tequila, mezcal, cocteles)", "Snacks mexicanos", "Juegos y karaoke", "Coordinador de experiencia"]', '2 horas', 'CDMX', '[{"cantidad": "1 - 3", "precio_pp": "$1,150.00 MXN"}, {"cantidad": "4 - 6", "precio_pp": "$1,050.00 MXN"}, {"cantidad": "7+", "precio_pp": "$950.00 MXN"}]') ON CONFLICT (slug) DO NOTHING;
