INSERT INTO public.experiences_escapamex (id, slug, title, category, description, short_description, price, price_max, currency, image, images, included, duration, location, tafiras) VALUES ('b455b650-6ee8-51b3-a226-2240660acdeb', 'experiencia-holbox-escape-paraiso-natural', 'Experiencia “Holbox Escape: Paraíso Natural”', 'Aventura', 'Descubre uno de los destinos más exclusivos y relajados del Caribe mexicano en una experiencia de día completo. Isla Holbox te cautivará con su arena blanca, calles sin pavimentar y aguas poco profundas de tonos turquesa. Durante el recorrido, navegarás hacia Isla Pasión y la Laguna Yalahau, donde podrás disfrutar de paisajes naturales únicos y un ambiente completamente desconectado del ritmo urbano.', 'Descubre uno de los destinos más exclusivos y relajados del Caribe mexicano en una experiencia de día completo. Isla Holbox te cautivará con su are...', 2780.0, NULL, 'MXN', 'https://addyourexperience.com/wp-content/uploads/2026/04/8-300x300.jpg', '["https://addyourexperience.com/wp-content/uploads/2026/04/8-300x300.jpg", "https://addyourexperience.com/wp-content/uploads/2026/04/8-2-300x300.jpg", "https://addyourexperience.com/wp-content/uploads/2026/04/8-3-300x300.jpg"]', '["Transporte redondo desde Cancún, Playa del Carmen o Tulum", "Guía bilingüe (español e inglés)", "Paseo en lancha a Isla Pasión y Laguna Yalahau", "Desayuno ligero", "Comida", "1 bebida durante el recorrido", "No incluye: Impuesto de muelle y área natural", "Importante: El punto de encuentro será confirmado una vez realizada la reserva, con el objetivo de optimizar la logística y garantizar una experiencia cómoda."]', '8 a 10 horas', 'Holbox', NULL) ON CONFLICT (slug) DO NOTHING;
